UPDATE user
nickname = #{nickname}, email = #{email}, user_pic = #{userPic}, bio = #{bio}, phone = #{phone}, role = #{role, typeHandler=com.itniuma.bitinn.config.MyBatisTypeHandlerConfig$UserRoleTypeHandler}, status = #{status, typeHandler=com.itniuma.bitinn.config.MyBatisTypeHandlerConfig$UserStatusTypeHandler}, update_time = #{updateTime}
WHERE id = #{id}

UPDATE user
SET user_pic = #{userPic}, update_time = NOW()
WHERE id = #{id}

UPDATE user
SET password = #{password}, update_time = NOW()
WHERE id = #{id}
